import torch
from torchvision import models, transforms
import requests
import json
from PIL import Image
import io

# Load pre-trained model and device (GPU if available)
device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
model = models.resnet50(pretrained=True).to(device)

def classify_image(image_bytes):
    # Convert image to tensor
    transform = transforms.Compose([
        transforms.Resize(256),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
    ])
    image_tensor = transform(Image.open(io.BytesIO(image_bytes)))

    # Run inference
    output = model(image_tensor.unsqueeze(0).to(device))
    _, predicted_class = torch.max(output, 1)
    confidence_score = torch.nn.functional.softmax(output, dim=1)[0][predicted_class].item()

    return predicted_class.item(), confidence_score

def api_handler(request):
    if request.method == 'POST':
        image_bytes = request.files['image'].read()
        class_id, confidence_score = classify_image(image_bytes)
        response = {
            "class": class_id,
            "confidence": confidence_score
        }
        return json.dumps(response), 200
    else:
        return "Invalid request method", 400

from flask import Flask, request, jsonify
app = Flask(__name__)

@app.route('/classify', methods=['POST'])
def classify():
    return api_handler(request)

if __name__ == '__main__':
    app.run(debug=True)